// src/components/TelaEsterilizacao.jsx
import React, { useState, useEffect } from 'react'
import axios from 'axios'
import { toast } from 'react-toastify'
import { Calendar } from 'lucide-react'  // ← adiciona esta linha

export default function TelaEsterilizacao() {
  const [codigo, setCodigo] = useState('')
  const [allCaixas, setAllCaixas] = useState([])
  const [caixas, setCaixas] = useState([])
  const [alunoPin, setAlunoPin] = useState('')
  const [historico, setHistorico] = useState([])
  const [searchTerm, setSearchTerm] = useState('')
  const [filterDate, setFilterDate] = useState('')

  // carrega todas as caixas para autocomplete
  useEffect(() => {
    axios.get('/api/caixas')
      .then(res => setAllCaixas(res.data))
      .catch(() => setAllCaixas([]))
  }, [])

  // recarrega histórico sempre que mudam as caixas selecionadas
  useEffect(() => {
    if (caixas.length === 0) {
      setHistorico([])
      return
    }
    axios.get('/api/movimentacoes')
      .then(res => {
        const ids = caixas.map(c => c.id)
        const filtrado = res.data.filter(m => ids.includes(m.caixa_id))
        setHistorico(filtrado)
      })
      .catch(() => setHistorico([]))
  }, [caixas])

  // sugestões de caixas enquanto digita
  const suggestions = codigo
    ? allCaixas.filter(c =>
        c.nome.toLowerCase().includes(codigo.toLowerCase()) ||
        c.codigo_barras.includes(codigo)
      ).slice(0, 5)
    : []

  const addCaixa = c => {
    if (caixas.some(x => x.id === c.id)) {
      toast.info('Caixa já adicionada.')
    } else {
      setCaixas(prev => [...prev, c])
      toast.success(`Caixa adicionada: ${c.nome}`)
    }
    setCodigo('')
  }

  const buscarCaixa = () => {
    const encontrada = allCaixas.find(c => c.codigo_barras === codigo)
    if (!encontrada) {
      toast.error('Caixa não encontrada pelo código.')
      return
    }
    addCaixa(encontrada)
  }

  const operar = async tipo => {
    if (caixas.length === 0) {
      toast.warn('Adicione ao menos uma caixa.')
      return
    }
    if (!alunoPin) {
      toast.warn('Informe o PIN do aluno.')
      return
    }

    if (tipo === 'saida') {
      const invalid = caixas.filter(c => {
        const hist = historico.filter(m => m.caixa_id === c.id)
        if (hist.length === 0) return true
        return hist[0].tipo !== 'entrada'
      })
      if (invalid.length > 0) {
        invalid.forEach(c =>
          toast.error(
            `Não é possível dar saída da caixa "${c.nome}" sem entrada pendente.`
          )
        )
        return
      }
    }

    try {
      await Promise.all(caixas.map(c =>
        axios.post(`/api/movimentacoes/${tipo}`, {
          caixa_id: c.id,
          aluno_pin: alunoPin
        })
      ))
      toast.success(`${tipo === 'entrada' ? 'Entrada' : 'Saída'} registrada!`)
      setAlunoPin('')
    } catch {
      toast.error(`Erro ao registrar ${tipo}.`)
    }
  }

  const removerCaixa = id => {
    setCaixas(prev => prev.filter(c => c.id !== id))
  }

  return (
    <div className="max-w-3xl mx-auto py-10 px-4 space-y-6">
      <h2 className="text-2xl font-bold">Controle de Esterilização</h2>

      {/* busca em card com autocomplete */}
      <div className="bg-white rounded-2xl shadow p-6">
        <div className="relative flex flex-col md:flex-row gap-4">
          <div className="relative flex-1">
            <input
              type="text"
              placeholder="Código ou nome da caixa"
              value={codigo}
              onChange={e => setCodigo(e.target.value)}
              onKeyDown={e => {
                if (e.key === 'Enter') {
                  e.preventDefault()
                  buscarCaixa()
                }
              }}
              className="w-full border rounded px-3 py-2"
            />
            {suggestions.length > 0 && (
              <ul className="absolute z-20 w-full bg-white border rounded max-h-40 overflow-y-auto mt-1">
                {suggestions.map(c => (
                  <li
                    key={c.id}
                    className="px-2 py-1 hover:bg-gray-100 cursor-pointer"
                    onClick={() => addCaixa(c)}
                  >
                    {c.nome} ({c.codigo_barras})
                  </li>
                ))}
              </ul>
            )}
          </div>
          <button
            onClick={buscarCaixa}
            className="w-full md:w-auto bg-blue-600 hover:bg-blue-700 text-white font-bold px-4 py-2 rounded-full"
          >
            Adicionar
          </button>
        </div>
      </div>

      {/* caixas selecionadas */}
      {caixas.length > 0 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <h3 className="text-lg font-medium mb-2">Caixas selecionadas</h3>
          <div className="flex flex-wrap gap-2">
            {caixas.map(c => (
              <div
                key={c.id}
                className="flex items-center bg-gray-100 px-3 py-1 rounded-full"
              >
                <span>{c.nome}</span>
                <button
                  onClick={() => removerCaixa(c.id)}
                  className="ml-2 text-gray-500"
                >
                  ×
                </button>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* operação */}
      {caixas.length > 0 && (
        <div className="bg-white rounded-2xl shadow p-6">
          <div className="flex flex-col md:flex-row gap-4">
            <input
              type="text"
              placeholder="PIN do aluno"
              value={alunoPin}
              onChange={e =>
                setAlunoPin(e.target.value.replace(/\D/g, '').slice(0, 4))
              }
              className="flex-1 border rounded px-3 py-2"
            />
            <button
              onClick={() => operar('entrada')}
              className="w-full md:w-auto bg-green-600 hover:bg-green-700 text-white font-bold px-4 py-2 rounded-full"
            >
              Entrada
            </button>
            <button
              onClick={() => operar('saida')}
              className="w-full md:w-auto bg-red-600 hover:bg-red-700 text-white font-bold px-4 py-2 rounded-full"
            >
              Saída
            </button>
          </div>
        </div>
      )}

      {/* histórico */}
      <div className="bg-white rounded-2xl shadow p-6">
        <h3 className="text-xl font-bold mb-4">Histórico</h3>

        {/* filtros: pesquisa e data */}
        <div className="flex flex-col md:flex-row md:items-center justify-between gap-2 mb-4">
          <input
            type="text"
            placeholder="Pesquisar movimentações..."
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className="flex-1 border rounded px-3 py-2"
          />
          <div className="relative">
            <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" />
            <input
              type="date"
              value={filterDate}
              onChange={e => setFilterDate(e.target.value)}
              className="border rounded px-3 py-2 pl-10"
            />
          </div>
        </div>

        {/* lista filtrada */}
        {(() => {
          const filtered = historico.filter(m => {
            const text = searchTerm.toLowerCase()
            const inText = [m.caixaNome, m.tipo, m.alunoNome, m.operadorNome]
              .some(field => field.toLowerCase().includes(text))
            const inDate = !filterDate ||
              new Date(m.criado_em).toISOString().slice(0,10) === filterDate
            return inText && inDate
          })
          if (filtered.length === 0) {
            return <p className="text-gray-500">Nenhuma movimentação registrada.</p>
          }
          return (
            <div className="space-y-4">
              {filtered.map(m => (
                <div
                  key={m.id}
                  className="bg-gray-50 rounded-xl p-4 md:flex md:items-center md:justify-between gap-4"
                >
                  <div className="flex-1">
                    <span className="font-semibold">Caixa: </span>{m.caixaNome}
                  </div>
                  <div className="flex-1">
                    <span className="font-semibold">Tipo: </span>{m.tipo}
                  </div>
                  <div className="flex-1">
                    <span className="font-semibold">Aluno: </span>{m.alunoNome}
                  </div>
                  <div className="flex-1">
                    <span className="font-semibold">Operador: </span>{m.operadorNome}
                  </div>
                  <div className="flex-1">
                    <span className="font-semibold">Data: </span>
                    {new Date(m.criado_em).toLocaleString()}
                  </div>
                </div>
              ))}
            </div>
          )
        })()}
      </div>
    </div>
  )
}
